#include <bits/stdc++.h>
using namespace std;
const int N=100005,inf=0x3f3f3f3f;
int n,q,a[N][25],fa[N][25];
int fun(int x,int y)
{
	int num=0;
	while(y)
	{
		if(y&1==1) x=fa[x][num];
		num++;
		y=y>>1;
	}
	return x;
}
int fun2(int x,int y)
{
	int num=0;
	while(y)
	{
		if(y&1==1) x=a[x][num];
		num++;
		y=y>>1;
	}
	return x;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>q;
	memset(a,0x3f,sizeof(a));
	fa[1][0]=1;
	for(int i=2;i<=n;i++)
	{
		cin>>fa[i][0];
		a[fa[i][0]][0]=min(a[fa[i][0]][0],i);
	}
	for(int i=1;i<=n;i++)
	{
		if(a[i][0]==inf) a[i][0]=i;
	}
	for(int i=1;i<=20;i++)
	{
		for(int j=1;j<=n;j++)
		{
			fa[j][i]=fa[fa[j][i-1]][i-1];
			a[j][i]=a[a[j][i-1]][i-1];
		}
	}
	while(q--) 
	{
		int s,k;
		cin>>s>>k;
		for(int j=1;j<=k;j++)
		{
			int x;
			cin>>x;
			if(x>0) s=fun(s,x);
			else s=fun2(s,-x);
		}
		cout<<s<<"\n";
	}
	return 0;
}
